import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as s,d as a}from"./app-b2b64365.js";const e={},l=a(`<h2 id="什么是异常" tabindex="-1"><a class="header-anchor" href="#什么是异常" aria-hidden="true">#</a> 什么是异常？</h2><p>异常即是一个事件，该事件会在程序执行过程中发生，影响了程序的正常执行。</p><p>一般情况下，在Python无法正常处理程序时就会发生一个异常。</p><p>异常是Python对象，表示一个错误。</p><p>当Python脚本发生异常时我们需要捕获处理它，否则程序会终止执行。</p><h2 id="python标准异常" tabindex="-1"><a class="header-anchor" href="#python标准异常" aria-hidden="true">#</a> python标准异常</h2><table><thead><tr><th style="text-align:left;">异常名称</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">BaseException</td><td style="text-align:left;">所有异常的基类</td></tr><tr><td style="text-align:left;">SystemExit</td><td style="text-align:left;">解释器请求退出</td></tr><tr><td style="text-align:left;">KeyboardInterrupt</td><td style="text-align:left;">用户中断执行(通常是输入^C)</td></tr><tr><td style="text-align:left;">Exception</td><td style="text-align:left;">常规错误的基类</td></tr><tr><td style="text-align:left;">StopIteration</td><td style="text-align:left;">迭代器没有更多的值</td></tr><tr><td style="text-align:left;">GeneratorExit</td><td style="text-align:left;">生成器(generator)发生异常来通知退出</td></tr><tr><td style="text-align:left;">StandardError</td><td style="text-align:left;">所有的内建标准异常的基类</td></tr><tr><td style="text-align:left;">ArithmeticError</td><td style="text-align:left;">所有数值计算错误的基类</td></tr><tr><td style="text-align:left;">FloatingPointError</td><td style="text-align:left;">浮点计算错误</td></tr><tr><td style="text-align:left;">OverflowError</td><td style="text-align:left;">数值运算超出最大限制</td></tr><tr><td style="text-align:left;">ZeroDivisionError</td><td style="text-align:left;">除(或取模)零 (所有数据类型)</td></tr><tr><td style="text-align:left;">AssertionError</td><td style="text-align:left;">断言语句失败</td></tr><tr><td style="text-align:left;">AttributeError</td><td style="text-align:left;">对象没有这个属性</td></tr><tr><td style="text-align:left;">EOFError</td><td style="text-align:left;">没有内建输入,到达EOF 标记</td></tr><tr><td style="text-align:left;">EnvironmentError</td><td style="text-align:left;">操作系统错误的基类</td></tr><tr><td style="text-align:left;">IOError</td><td style="text-align:left;">输入/输出操作失败</td></tr><tr><td style="text-align:left;">OSError</td><td style="text-align:left;">操作系统错误</td></tr><tr><td style="text-align:left;">WindowsError</td><td style="text-align:left;">系统调用失败</td></tr><tr><td style="text-align:left;">ImportError</td><td style="text-align:left;">导入模块/对象失败</td></tr><tr><td style="text-align:left;">LookupError</td><td style="text-align:left;">无效数据查询的基类</td></tr><tr><td style="text-align:left;">IndexError</td><td style="text-align:left;">序列中没有此索引(index)</td></tr><tr><td style="text-align:left;">KeyError</td><td style="text-align:left;">映射中没有这个键</td></tr><tr><td style="text-align:left;">MemoryError</td><td style="text-align:left;">内存溢出错误(对于Python 解释器不是致命的)</td></tr><tr><td style="text-align:left;">NameError</td><td style="text-align:left;">未声明/初始化对象 (没有属性)</td></tr><tr><td style="text-align:left;">UnboundLocalError</td><td style="text-align:left;">访问未初始化的本地变量</td></tr><tr><td style="text-align:left;">ReferenceError</td><td style="text-align:left;">弱引用(Weak reference)试图访问已经垃圾回收了的对象</td></tr><tr><td style="text-align:left;">RuntimeError</td><td style="text-align:left;">一般的运行时错误</td></tr><tr><td style="text-align:left;">NotImplementedError</td><td style="text-align:left;">尚未实现的方法</td></tr><tr><td style="text-align:left;">SyntaxError</td><td style="text-align:left;">Python 语法错误</td></tr><tr><td style="text-align:left;">IndentationError</td><td style="text-align:left;">缩进错误</td></tr><tr><td style="text-align:left;">TabError</td><td style="text-align:left;">Tab 和空格混用</td></tr><tr><td style="text-align:left;">SystemError</td><td style="text-align:left;">一般的解释器系统错误</td></tr><tr><td style="text-align:left;">TypeError</td><td style="text-align:left;">对类型无效的操作</td></tr><tr><td style="text-align:left;">ValueError</td><td style="text-align:left;">传入无效的参数</td></tr><tr><td style="text-align:left;">UnicodeError</td><td style="text-align:left;">Unicode 相关的错误</td></tr><tr><td style="text-align:left;">UnicodeDecodeError</td><td style="text-align:left;">Unicode 解码时的错误</td></tr><tr><td style="text-align:left;">UnicodeEncodeError</td><td style="text-align:left;">Unicode 编码时错误</td></tr><tr><td style="text-align:left;">UnicodeTranslateError</td><td style="text-align:left;">Unicode 转换时错误</td></tr><tr><td style="text-align:left;">Warning</td><td style="text-align:left;">警告的基类</td></tr><tr><td style="text-align:left;">DeprecationWarning</td><td style="text-align:left;">关于被弃用的特征的警告</td></tr><tr><td style="text-align:left;">FutureWarning</td><td style="text-align:left;">关于构造将来语义会有改变的警告</td></tr><tr><td style="text-align:left;">OverflowWarning</td><td style="text-align:left;">旧的关于自动提升为长整型(long)的警告</td></tr><tr><td style="text-align:left;">PendingDeprecationWarning</td><td style="text-align:left;">关于特性将会被废弃的警告</td></tr><tr><td style="text-align:left;">RuntimeWarning</td><td style="text-align:left;">可疑的运行时行为(runtime behavior)的警告</td></tr><tr><td style="text-align:left;">SyntaxWarning</td><td style="text-align:left;">可疑的语法的警告</td></tr><tr><td style="text-align:left;">UserWarning</td><td style="text-align:left;">用户代码生成的警告</td></tr></tbody></table><h2 id="异常处理" tabindex="-1"><a class="header-anchor" href="#异常处理" aria-hidden="true">#</a> 异常处理</h2><h3 id="try-except语句" tabindex="-1"><a class="header-anchor" href="#try-except语句" aria-hidden="true">#</a> try/except语句</h3><p>try/except语句用来检测try语句块中的错误，从而让except语句捕获异常信息并处理。</p><p>如果你不想在异常发生时结束你的程序，只需在try里捕获它。</p><p>语法：</p><p>以下为简单的*<code>try....except...else</code>*的语法：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>        <span class="token comment">#运行别的代码</span>
<span class="token keyword">except</span> <span class="token operator">&lt;</span>异常类型<span class="token operator">&gt;</span>：
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>        <span class="token comment">#如果在try部份引发了异常</span>
<span class="token keyword">else</span><span class="token punctuation">:</span>
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>        <span class="token comment">#如果没有异常发生</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>try的工作原理是，当开始一个try语句后，python就在当前程序的上下文中作标记，这样当异常出现时就可以回到这里，try子句先执行，接下来会发生什么依赖于执行时是否出现异常。</p><ul><li>如果当try后的语句执行时发生异常，python就跳回到try并执行第一个匹配该异常的except子句，异常处理完毕，控制流就通过整个try语句（除非在处理异常时又引发新的异常）。</li><li>如果在try后的语句里发生了异常，却没有匹配的except子句，异常将被递交到上层的try，或者到程序的最上层（这样将结束程序，并打印默认的出错信息）。</li><li>如果在try子句执行时没有发生异常，python将执行else语句后的语句（如果有else的话），然后控制流通过整个try语句。</li></ul><h4 id="使用except而不带任何异常类型" tabindex="-1"><a class="header-anchor" href="#使用except而不带任何异常类型" aria-hidden="true">#</a> 使用except而不带任何异常类型</h4><p>你可以不带任何异常类型使用except，如下实例：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    a <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token string">&#39;a.0&#39;</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token number">1</span>
<span class="token keyword">except</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;error&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">else</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上方式try-except语句捕获所有发生的异常。但这不是一个很好的方式，我们不能通过该程序识别出具体的异常信息。因为它捕获所有的异常。</p><h4 id="使用except而带多种异常类型" tabindex="-1"><a class="header-anchor" href="#使用except而带多种异常类型" aria-hidden="true">#</a> 使用except而带多种异常类型</h4><p>你也可以使用相同的except语句来处理多个异常信息，如下所示：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token string">&#39;a.0&#39;</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token number">1</span>
<span class="token keyword">except</span> <span class="token punctuation">(</span>SyntaxError<span class="token punctuation">,</span> ValueError<span class="token punctuation">)</span> <span class="token keyword">as</span> e<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当然，也可以分开捕获多种异常：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token string">&#39;a.0&#39;</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token number">1</span>
<span class="token keyword">except</span> SyntaxError <span class="token keyword">as</span> e<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&#39;1: </span><span class="token interpolation"><span class="token punctuation">{</span>e<span class="token punctuation">}</span></span><span class="token string">&#39;</span></span><span class="token punctuation">)</span>
<span class="token keyword">except</span> ValueError <span class="token keyword">as</span> e<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&#39;2: </span><span class="token interpolation"><span class="token punctuation">{</span>e<span class="token punctuation">}</span></span><span class="token string">&#39;</span></span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="异常的参数" tabindex="-1"><a class="header-anchor" href="#异常的参数" aria-hidden="true">#</a> 异常的参数</h4><p>一个异常可以带上参数，可作为输出的异常信息参数。</p><p>你可以通过except语句来捕获异常的参数，如下所示：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    a <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token string">&#39;a.0&#39;</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token number">1</span>
<span class="token keyword">except</span> ValueError <span class="token keyword">as</span> val<span class="token punctuation">:</span> <span class="token comment"># 参数val中存储具体的异常信息</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>val<span class="token punctuation">)</span>  
<span class="token keyword">else</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>变量接收的异常值通常包含在异常的语句中。在元组的表单中变量可以接收一个或者多个值。</p><p>元组通常包含错误字符串，错误数字，错误位置。</p><h3 id="try-finally-语句" tabindex="-1"><a class="header-anchor" href="#try-finally-语句" aria-hidden="true">#</a> try-finally 语句</h3><p>try-finally 语句无论是否发生异常都将执行最后的代码。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>
<span class="token keyword">except</span> <span class="token operator">&lt;</span>异常类型<span class="token operator">&gt;</span>：
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>        <span class="token comment"># 发生异常时执行的代码</span>
<span class="token keyword">else</span><span class="token punctuation">:</span>
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>        <span class="token comment"># 没有发生异常时执行的代码</span>
<span class="token keyword">finally</span><span class="token punctuation">:</span>
	<span class="token operator">&lt;</span>语句<span class="token operator">&gt;</span>    <span class="token comment"># 不管有没有异常都会执行的代码</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="抛出异常" tabindex="-1"><a class="header-anchor" href="#抛出异常" aria-hidden="true">#</a> 抛出异常</h2><p>Python 使用 raise 语句抛出一个指定的异常。</p><p>raise语法格式如下：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">raise</span> <span class="token punctuation">[</span>Exception <span class="token punctuation">[</span><span class="token punctuation">,</span> args <span class="token punctuation">[</span><span class="token punctuation">,</span> traceback<span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>以下实例如果 x 大于 5 就触发异常:</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>x <span class="token operator">=</span> <span class="token number">10</span>
<span class="token keyword">if</span> x <span class="token operator">&gt;</span> <span class="token number">5</span><span class="token punctuation">:</span>
    <span class="token keyword">raise</span> Exception<span class="token punctuation">(</span><span class="token string">&#39;x 不能大于 5。x 的值为: {}&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="用户自定义异常" tabindex="-1"><a class="header-anchor" href="#用户自定义异常" aria-hidden="true">#</a> 用户自定义异常</h2><p>你可以通过创建一个新的异常类来拥有自己的异常。异常类继承自 Exception 类，可以直接继承，或者间接继承，例如:</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 自定义错误类型</span>
<span class="token keyword">class</span> <span class="token class-name">ArgsError</span><span class="token punctuation">(</span>Exception<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> num<span class="token punctuation">,</span> num_type<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>num <span class="token operator">=</span> num  <span class="token comment"># 用来描述参数个数</span>
        self<span class="token punctuation">.</span>num_type <span class="token operator">=</span> num_type  <span class="token comment"># 用户描述参数类型</span>


num1 <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token string">&quot;输入数字:&quot;</span><span class="token punctuation">)</span>
num2 <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token string">&quot;输入数字:&quot;</span><span class="token punctuation">)</span>

<span class="token keyword">try</span><span class="token punctuation">:</span>
    <span class="token keyword">if</span> num1<span class="token punctuation">.</span>isdigit<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">is</span> <span class="token boolean">False</span> <span class="token keyword">or</span> num2<span class="token punctuation">.</span>isdigit<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">is</span> <span class="token boolean">False</span><span class="token punctuation">:</span>
             <span class="token comment"># 错误类型的实例对象</span>
        <span class="token keyword">raise</span> ArgsError<span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&quot;int&quot;</span><span class="token punctuation">)</span>  <span class="token comment"># raise 异常类型  -&gt; 主动抛出异常</span>
<span class="token keyword">except</span> ArgsError <span class="token keyword">as</span> ret<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;需要%d个%s参数&quot;</span> <span class="token operator">%</span> <span class="token punctuation">(</span>ret<span class="token punctuation">.</span>num<span class="token punctuation">,</span> ret<span class="token punctuation">.</span>num_type<span class="token punctuation">)</span><span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>大多数的异常的名字都以&quot;Error&quot;结尾，就跟标准的异常命名一样。</p>`,44),p=[l];function o(r,i){return n(),s("div",null,p)}const u=t(e,[["render",o],["__file","python异常.html.vue"]]);export{u as default};
